import java.util.*;

public int maxQualityRec(int[][] adjMatrix, int[] values, int node, int timeLeft, Set<Integer> visited) {
    if (timeLeft < 0) {
        return Integer.MIN_VALUE;
    }

    int maxQuality = 0;
    visited.add(node);
    for (int i = 0; i < adjMatrix[node].length; ++i) {
        if (adjMatrix[node][i] != -1) {
            int time = adjMatrix[node][i];
            int oldValue = adjMatrix[node][i];
            adjMatrix[node][i] = adjMatrix[i][node] = -1;
            maxQuality = Math.max(maxQuality, maxQualityRec(adjMatrix, values, i, timeLeft - time, visited));
            adjMatrix[node][i] = adjMatrix[i][node] = oldValue;
        }
    }
    visited.remove(node);
    return maxQuality + (visited.contains(node + 1) ? 0 : values[node]);
}

public int maxQuality(int n, int[] values, int[][] edges, int maxTime) {
    int[][] adjMatrix = new int[n][n];
    for (int[] row : adjMatrix) {
        Arrays.fill(row, -1);
    }

    for (int[] edge : edges) {
        adjMatrix[edge[0]][edge[1]] = adjMatrix[edge[1]][edge[0]] = edge[2];
    }

    Set<Integer> visited = new HashSet<>();
    return maxQualityRec(adjMatrix, values, 0, maxTime, visited);
}
